use quick_xml::Reader;
use std::io::prelude::*;

fn parse_xml_config(xml_data: &[u8]) -> Result<Config, String> {
    let mut reader = Reader::from_str(std::str::from_utf8(xml_data)?)?;
    reader.trim_text(true);

    let mut config = Config::default();

    for e in reader.read_to_end()? {
        match e {
            Ok(e) => {
                let tag = e.name().into_inner();
                let value = e.text().unwrap_or("").into_owned();

                if tag == "setting" {
                    let name = e.attributes().find("name").unwrap().value().unwrap();
                    config.settings.insert(name.into_owned(), value);
                }
            }
            Err(e) => return Err(format!("Error parsing XML: {}", e)),
        }
    }

    Ok(config)
}

